sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading) {
    if (isLoading) return;

    g_form.clearOptions('servicenow_close_code');
    g_form.setValue('servicenow_close_code', '');

    if (!newValue) return;

    g_form.addOption('servicenow_close_code', '', '-- Select Close Code --');

    var ga = new GlideAjax('PulseCategoryAjax'); // whatever your Script Include is called
    ga.addParam('sysparm_name', 'getCloseCodes');
    ga.addParam('sysparm_table', newValue);

    ga.getXMLAnswer(function (answer) {
        if (!answer) return;

        var codes = JSON.parse(answer);
        for (var i = 0; i < codes.length; i++) {
            g_form.addOption('servicenow_close_code', codes[i].value, codes[i].label);
        }
    });
}
